export type Check = {
  name: string;
  pass: boolean;
  metadata?: Record<string, unknown>;
  children?: Check[];
};

export type ResolveStatus = 'ready' | 'stale_refresh_queued' | 'queued';

export type ResolveResult = {
  canonicalUrl: string;
  slug: string;
  status: ResolveStatus;
  trackedSiteId: string;
};

export type ScoreResponse = {
  canonicalUrl: string;
  checks: Check[];
  computedAt: string;
  name: string;
  overallScore: number;
  passedChecks: number;
  slug: string;
  totalChecks: number;
};
